function handler(event) {
  var request = event.request;
  var uri = request.uri;

  // If URI has a file extension, serve as-is (JS, CSS, images, etc.)
  if (uri.includes('.')) {
    return request;
  }

  // Append trailing slash if missing, then index.html
  if (!uri.endsWith('/')) {
    uri += '/';
  }
  request.uri = uri + 'index.html';

  return request;
}

